export class UsuariosComponent {
  constructor(usuarioService, rolService, authService) {
    this.usuarioService = usuarioService;
    this.rolService = rolService;
    this.authService = authService;
    this.usuarios = [];
    this.usuarioSeleccionado = this.nuevoUsuario();
    this.nuevoPassword = '';
    this.mostrandoModal = false;
    this.mostrandoCambioPassword = false;
    this.usuarioParaPassword = null;
    this.passwordNuevo = '';
    this.passwordConfirmar = '';
    this.roles = [];
    this.nuevoRolInput = '';
    this.nuevoRolDesc = '';
    this.guardandoRol = false;
    // Paleta de colores generada deterministicamente por nombre de rol
    this.PALETA = ['#9b59b6', '#3498db', '#2ecc71', '#e67e22', '#e74c3c', '#1abc9c', '#2980b9', '#8e44ad', '#27ae60', '#d35400', '#c0392b', '#16a085', '#2c3e50', '#7f8c8d', '#f39c12'];
  }
  ngOnInit() {
    this.currentUserId = this.authService.currentUserValue?.id;
    this.cargarUsuarios();
    this.cargarRoles();
  }
  cargarRoles() {
    this.rolService.obtenerTodos().subscribe({
      next: data => this.roles = data,
      error: err => console.error('Error al cargar roles:', err)
    });
  }
  cargarUsuarios() {
    this.usuarioService.obtenerTodos().subscribe({
      next: data => this.usuarios = data,
      error: err => console.error('Error al cargar usuarios:', err)
    });
  }
  agregarNuevoRol() {
    const nombre = this.nuevoRolInput.trim().toUpperCase();
    if (!nombre) return;
    // Si ya existe en el catálogo, solo asignarlo
    const existente = this.roles.find(r => r.nombre === nombre);
    if (existente) {
      this.toggleRolPorNombre(nombre, true);
      this.nuevoRolInput = '';
      return;
    }
    // Crear en BD
    this.guardandoRol = true;
    this.rolService.crear({
      nombre,
      descripcion: this.nuevoRolDesc.trim() || undefined
    }).subscribe({
      next: rolCreado => {
        this.roles = [...this.roles, rolCreado].sort((a, b) => a.nombre.localeCompare(b.nombre));
        this.toggleRolPorNombre(rolCreado.nombre, true);
        this.nuevoRolInput = '';
        this.nuevoRolDesc = '';
        this.guardandoRol = false;
      },
      error: err => {
        this.guardandoRol = false;
        Swal.fire({
          icon: 'error',
          title: 'Error',
          text: err?.error?.error || 'No se pudo crear el rol'
        });
      }
    });
  }
  eliminarRolCatalogo(rol, event) {
    event.stopPropagation();
    Swal.fire({
      title: `¿Eliminar rol "${rol.nombre}"?`,
      text: 'Se eliminará del catálogo, pero los usuarios que ya lo tienen lo conservarán.',
      icon: 'warning',
      showCancelButton: true,
      confirmButtonColor: '#d33',
      confirmButtonText: 'Sí, eliminar',
      cancelButtonText: 'Cancelar'
    }).then(result => {
      if (result.isConfirmed) {
        this.rolService.eliminar(rol.id).subscribe({
          next: () => {
            this.roles = this.roles.filter(r => r.id !== rol.id);
          },
          error: err => Swal.fire({
            icon: 'error',
            title: 'Error',
            text: err?.error?.error || 'No se pudo eliminar'
          })
        });
      }
    });
  }
  toggleRolPorNombre(nombre, checked) {
    if (checked && !this.usuarioSeleccionado.roles.includes(nombre)) {
      this.usuarioSeleccionado.roles = [...this.usuarioSeleccionado.roles, nombre];
    } else if (!checked) {
      this.usuarioSeleccionado.roles = this.usuarioSeleccionado.roles.filter(r => r !== nombre);
    }
  }
  abrirNuevo() {
    this.usuarioSeleccionado = this.nuevoUsuario();
    this.nuevoPassword = '';
    this.nuevoRolInput = '';
    this.nuevoRolDesc = '';
    this.mostrandoModal = true;
  }
  editar(usuario) {
    this.usuarioSeleccionado = {
      ...usuario,
      roles: [...usuario.roles]
    };
    this.nuevoPassword = '';
    this.nuevoRolInput = '';
    this.nuevoRolDesc = '';
    this.mostrandoModal = true;
  }
  cancelar() {
    this.mostrandoModal = false;
    this.usuarioSeleccionado = this.nuevoUsuario();
    this.nuevoPassword = '';
    this.nuevoRolInput = '';
    this.nuevoRolDesc = '';
  }
  cerrarAlHacerClick(event) {
    if (event.target.classList.contains('modal-overlay')) {
      this.cancelar();
    }
  }
  cerrarPasswordModal(event) {
    if (event.target.classList.contains('modal-overlay')) {
      this.mostrandoCambioPassword = false;
    }
  }
  tieneRol(rol) {
    return this.usuarioSeleccionado.roles.includes(rol);
  }
  toggleRol(rol, event) {
    const checked = event.target.checked;
    if (checked && !this.usuarioSeleccionado.roles.includes(rol)) {
      this.usuarioSeleccionado.roles = [...this.usuarioSeleccionado.roles, rol];
    } else if (!checked) {
      this.usuarioSeleccionado.roles = this.usuarioSeleccionado.roles.filter(r => r !== rol);
