      payload.password = this.nuevoPassword;
    } else if (this.nuevoPassword) {
      // Editar: password solo si se llenó
      payload.password = this.nuevoPassword;
    }
    const op = this.usuarioSeleccionado.id ? this.usuarioService.actualizar(this.usuarioSeleccionado.id, payload) : this.usuarioService.crear(payload);
    op.subscribe({
      next: () => {
        Swal.fire({
          icon: 'success',
          title: this.usuarioSeleccionado.id ? 'Usuario actualizado' : 'Usuario creado',
          timer: 1500,
          showConfirmButton: false
        });
