          title: 'Contraseña actualizada',
          timer: 1500,
          showConfirmButton: false
        });
        this.mostrandoCambioPassword = false;
      },
      error: err => {
        const msg = err?.error?.error || 'Error al cambiar contraseña';
        Swal.fire({
          icon: 'error',
          title: 'Error',
          text: msg
        });
      }
    });
  }
